export type LaravelColumnType = 
  | 'id' 
  | 'string' 
  | 'text' 
  | 'integer' 
  | 'bigInteger' 
  | 'boolean' 
  | 'decimal' 
  | 'float' 
  | 'date' 
  | 'dateTime' 
  | 'timestamp' 
  | 'json'
  | 'foreignId';

export interface Column {
  id: string;
  name: string;
  type: LaravelColumnType;
  nullable: boolean;
  unique: boolean;
  default?: string;
  isPrimaryKey?: boolean;
}

export interface TableData {
  name: string;
  columns: Column[];
  comment?: string;
  color?: string; // For UI aesthetics
}

// React Flow specific types extension
import { Node, Edge } from 'reactflow';

export type TableNode = Node<TableData>;
export type RelationEdge = Edge;

export interface GeneratedCode {
  filename: string;
  content: string;
  type: 'migration' | 'model';
}

import { GoogleGenAI, Type } from "@google/genai";
import { TableNode, RelationEdge } from "../types";
import { v4 as uuidv4 } from 'uuid';

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment");
  }
  return new GoogleGenAI({ apiKey });
};

export const generateSchemaFromPrompt = async (prompt: string): Promise<{ nodes: TableNode[], edges: RelationEdge[] }> => {
  try {
    const ai = getClient();

    // We request a structured JSON response
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a database schema for a Laravel application based on this description: "${prompt}".

      Return a JSON object with:
      1. 'tables': Array of objects with 'name' (string) and 'columns' (array of objects with 'name', 'type', 'nullable', 'unique').
         - Supported types: string, integer, text, boolean, decimal, date, datetime, timestamp, json, foreignId.
         - Ensure 'id' and timestamps are NOT included in the list, I will add them automatically.
      2. 'relationships': Array of objects with 'sourceTable', 'targetTable', 'type' (hasOne, hasMany, belongsToMany).
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            tables: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  columns: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        name: { type: Type.STRING },
                        type: { type: Type.STRING },
                        nullable: { type: Type.BOOLEAN },
                        unique: { type: Type.BOOLEAN }
                      }
                    }
                  }
                }
              }
            },
            relationships: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  sourceTable: { type: Type.STRING },
                  targetTable: { type: Type.STRING },
                  type: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text);

    const nodes: TableNode[] = [];
    const edges: RelationEdge[] = [];
    const tableIdMap: Record<string, string> = {};

    // Generate Nodes
    let xOffset = 0;
    let yOffset = 0;
    const spacingX = 350;
    const spacingY = 0; // Simple horizontal layout for now, or grid

    data.tables.forEach((table: any, index: number) => {
      const id = uuidv4();
      tableIdMap[table.name] = id;

      // Basic Grid Layout Logic
      const col = index % 3;
      const row = Math.floor(index / 3);

      nodes.push({
        id,
        type: 'table',
        position: { x: col * 400 + 50, y: row * 400 + 50 },
        data: {
          name: table.name.toLowerCase(),
          columns: [
            { id: uuidv4(), name: 'id', type: 'id', nullable: false, unique: true, isPrimaryKey: true },
            ...table.columns.map((c: any) => ({
              id: uuidv4(),
              name: c.name,
              type: c.type || 'string',
              nullable: !!c.nullable,
              unique: !!c.unique
            })),
            { id: uuidv4(), name: 'created_at', type: 'timestamp', nullable: true, unique: false },
            { id: uuidv4(), name: 'updated_at', type: 'timestamp', nullable: true, unique: false },
          ],
          color: '#3b82f6' // Default Blue
        }
      });
    });

    // Generate Edges
    data.relationships.forEach((rel: any) => {
      const sourceId = tableIdMap[rel.sourceTable];
      const targetId = tableIdMap[rel.targetTable];

      if (sourceId && targetId) {
        edges.push({
          id: `e-${sourceId}-${targetId}`,
          source: sourceId,
          target: targetId,
          type: 'smoothstep',
          animated: true,
          label: rel.type
        });
      }
    });

    return { nodes, edges };

  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

import { TableNode, RelationEdge, GeneratedCode, Column } from '../types';

export const generateLaravelMigrations = (nodes: TableNode[], edges: RelationEdge[]): GeneratedCode[] => {
  const codes: GeneratedCode[] = [];
  const timestamp = new Date().toISOString().replace(/[-T:.Z]/g, '').slice(0, 14);

  nodes.forEach((node, index) => {
    const tableName = node.data.name;
    const className = `Create${tableName.charAt(0).toUpperCase() + tableName.slice(1)}Table`;
    const filename = `${timestamp}_${String(index).padStart(3, '0')}_create_${tableName}_table.php`;

    // Calculate foreign keys coming INTO this table
    const foreignKeys = edges
      .filter(edge => edge.target === node.id)
      .map(edge => {
        const sourceNode = nodes.find(n => n.id === edge.source);
        if (!sourceNode) return '';
        // Assuming typical Laravel convention: source_id
        const sourceNameSingular = sourceNode.data.name.endsWith('s') 
          ? sourceNode.data.name.slice(0, -1) 
          : sourceNode.data.name;

        return `            $table->foreignId('${sourceNameSingular}_id')->constrained('${sourceNode.data.name}')->onDelete('cascade');`;
      });

    const columnDefinitions = node.data.columns.map(col => generateColumnLine(col)).join('\n');

    const content = `<?php

use Illuminate\\Database\\Migrations\\Migration;
use Illuminate\\Database\\Schema\\Blueprint;
use Illuminate\\Support\\Facades\\Schema;

return new class extends Migration
{
    /**
     * Run the migrations.
     */
    public function up(): void
    {
        Schema::create('${tableName}', function (Blueprint $table) {
${columnDefinitions}
${foreignKeys.length > 0 ? '\n' + foreignKeys.join('\n') : ''}
        });
    }

    /**
     * Reverse the migrations.
     */
    public function down(): void
    {
        Schema::dropIfExists('${tableName}');
    }
};`;

    codes.push({
      filename,
      content,
      type: 'migration'
    });
  });

  return codes;
};

const generateColumnLine = (col: Column): string => {
  if (col.type === 'id') return `            $table->id();`;

  let line = `            $table->${col.type}('${col.name}')`;

  if (col.nullable) line += `->nullable()`;
  if (col.unique) line += `->unique()`;
  if (col.default) line += `->default('${col.default}')`; // Simple default handling

  line += `;`;
  return line;
};

import React from 'react';
import { Column, LaravelColumnType } from '../types';
import { COLUMN_TYPES } from '../constants';
import { X, Key } from 'lucide-react';

interface ColumnRowProps {
  column: Column;
  onUpdate: (id: string, field: keyof Column, value: any) => void;
  onRemove: (id: string) => void;
}

export const ColumnRow: React.FC<ColumnRowProps> = ({ column, onUpdate, onRemove }) => {
  return (
    <div className="flex items-center gap-1 py-1 px-1 hover:bg-black/5 rounded group relative">
      {/* Primary Key Indicator */}
      <div className="w-4 flex justify-center text-yellow-500">
        {column.type === 'id' && <Key size={12} fill="currentColor" />}
      </div>

      {/* Column Name Input */}
      <input 
        type="text" 
        value={column.name}
        onChange={(e) => onUpdate(column.id, 'name', e.target.value)}
        className="nodrag w-28 bg-transparent text-xs font-mono border-b border-transparent focus:border-blue-500 outline-none px-1 text-slate-700"
        placeholder="col_name"
      />

      {/* Type Selector */}
      <select
        value={column.type}
        onChange={(e) => onUpdate(column.id, 'type', e.target.value as LaravelColumnType)}
        className="nodrag w-24 bg-transparent text-[10px] text-slate-500 font-medium uppercase outline-none cursor-pointer hover:text-slate-700"
      >
        {COLUMN_TYPES.map(t => (
          <option key={t} value={t}>{t}</option>
        ))}
      </select>

      {/* Toggles */}
      <div className="flex gap-1 ml-auto opacity-0 group-hover:opacity-100 transition-opacity">
        <button 
          onClick={() => onUpdate(column.id, 'nullable', !column.nullable)}
          className={`px-1 text-[9px] rounded border ${column.nullable ? 'bg-blue-100 border-blue-200 text-blue-700' : 'border-slate-200 text-slate-400'}`}
          title="Nullable"
        >
          N
        </button>
        <button 
          onClick={() => onUpdate(column.id, 'unique', !column.unique)}
          className={`px-1 text-[9px] rounded border ${column.unique ? 'bg-purple-100 border-purple-200 text-purple-700' : 'border-slate-200 text-slate-400'}`}
          title="Unique"
        >
          U
        </button>
        <button 
          onClick={() => onRemove(column.id)}
          className="p-0.5 text-slate-400 hover:text-red-500"
        >
          <X size={12} />
        </button>
      </div>
    </div>
  );
};

import React, { memo } from 'react';
import { Handle, Position, NodeProps } from 'reactflow';
import { TableData } from '../types';
import { ColumnRow } from './ColumnRow';
import { Plus, GripVertical, Trash2 } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { COLORS } from '../constants';

const TableNode = ({ id, data }: NodeProps<TableData>) => {

  // Handlers would typically be passed down via context or custom props, 
  // but React Flow data object is mutable. We can also use a store pattern.
  // For simplicity in this demo, we assume data holds methods or we dispatch globally.
  // We will emit events via the `data.onUpdate` callback pattern if provided, 
  // OR we rely on the parent component to force updates.
  // For a strictly controlled component, we should use the React Flow `useReactFlow` hook to update node data.

  // Since we can't easily pass functions into `data` during serialization/AI gen, 
  // we'll dispatch CustomEvents that the main App listens to, strictly for this demo architecture.

  const dispatchUpdate = (newData: Partial<TableData>) => {
    const event = new CustomEvent('node-data-update', {
      detail: { id, data: newData }
    });
    window.dispatchEvent(event);
  };

  const dispatchDelete = () => {
    const event = new CustomEvent('node-delete', { detail: { id } });
    window.dispatchEvent(event);
  }

  const addColumn = () => {
    const newCol = { 
      id: uuidv4(), 
      name: 'new_column', 
      type: 'string', 
      nullable: false, 
      unique: false 
    };
    dispatchUpdate({
      columns: [...data.columns, newCol] // @ts-ignore
    });
  };

  const updateColumn = (colId: string, field: string, value: any) => {
    const newCols = data.columns.map(c => 
      c.id === colId ? { ...c, [field]: value } : c
    );
    dispatchUpdate({ columns: newCols });
  };

  const removeColumn = (colId: string) => {
    dispatchUpdate({ columns: data.columns.filter(c => c.id !== colId) });
  };

  const changeColor = (color: string) => {
    dispatchUpdate({ color });
  };

  return (
    <div className="bg-white rounded-lg shadow-xl border border-slate-200 w-[280px] overflow-hidden text-sm flex flex-col">
      {/* Handles for connections */}
      <Handle type="target" position={Position.Left} className="!bg-slate-400 !w-3 !h-3 -ml-1.5" />
      <Handle type="source" position={Position.Right} className="!bg-slate-400 !w-3 !h-3 -mr-1.5" />

      {/* Header */}
      <div 
        className="px-3 py-2 flex items-center justify-between handle relative" 
        style={{ backgroundColor: data.color || '#3b82f6' }}
      >
        <div className="flex items-center gap-2 flex-1">
          <GripVertical size={14} className="text-white/50 cursor-grab active:cursor-grabbing" />
          <input 
            className="nodrag bg-transparent text-white font-bold placeholder-white/70 outline-none w-full"
            value={data.name}
            onChange={(e) => dispatchUpdate({ name: e.target.value })}
            placeholder="Table Name"
          />
        </div>
        <div className="flex items-center gap-1">
          {/* Color Picker (Hidden till hover usually, but let's put a small dot) */}
          <div className="group relative">
             <div className="w-3 h-3 rounded-full bg-white/30 cursor-pointer hover:bg-white border border-white/40"></div>
             <div className="absolute right-0 top-full mt-1 hidden group-hover:flex gap-1 p-1 bg-white shadow-lg rounded-md z-50 w-32 flex-wrap">
                {COLORS.map(c => (
                  <div 
                    key={c} 
                    className="w-4 h-4 rounded-full cursor-pointer hover:scale-110" 
                    style={{backgroundColor: c}}
                    onClick={() => changeColor(c)}
                  />
                ))}
             </div>
          </div>
          <button onClick={dispatchDelete} className="text-white/70 hover:text-white">
            <Trash2 size={14} />
          </button>
        </div>
      </div>

      {/* Columns List */}
      <div className="flex flex-col bg-white min-h-[50px] divide-y divide-slate-50">
        {data.columns.map((col) => (
          <ColumnRow 
            key={col.id} 
            column={col} 
            onUpdate={updateColumn} 
            onRemove={removeColumn} 
          />
        ))}
      </div>

      {/* Footer */}
      <button 
        onClick={addColumn}
        className="flex items-center justify-center gap-1 py-1.5 bg-slate-50 text-slate-500 hover:bg-slate-100 hover:text-slate-700 transition-colors border-t border-slate-100 text-xs font-medium"
      >
        <Plus size={12} /> Add Column
      </button>
    </div>
  );
};

export default memo(TableNode);

