import React, { memo } from 'react';
import { Handle, Position, NodeProps } from 'reactflow';
// FIX: Import LaravelColumnType to correctly type new columns.
import { TableData, LaravelColumnType } from '../types';
import { ColumnRow } from './ColumnRow';
import { Plus, GripVertical, Trash2 } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { COLORS } from '../constants';

const TableNode = ({ id, data }: NodeProps<TableData>) => {

  // Handlers would typically be passed down via context or custom props, 
  // but React Flow data object is mutable. We can also use a store pattern.
  // For simplicity in this demo, we assume data holds methods or we dispatch globally.
  // We will emit events via the `data.onUpdate` callback pattern if provided, 
  // OR we rely on the parent component to force updates.
  // For a strictly controlled component, we should use the React Flow `useReactFlow` hook to update node data.

  // Since we can't easily pass functions into `data` during serialization/AI gen, 
  // we'll dispatch CustomEvents that the main App listens to, strictly for this demo architecture.

  const dispatchUpdate = (newData: Partial<TableData>) => {
    const event = new CustomEvent('node-data-update', {
      detail: { id, data: newData }
    });
    window.dispatchEvent(event);
  };

  const dispatchDelete = () => {
    const event = new CustomEvent('node-delete', { detail: { id } });
    window.dispatchEvent(event);
  }

  const addColumn = () => {
    const newCol = { 
      id: uuidv4(), 
      name: 'new_column', 
      // FIX: Cast 'string' to LaravelColumnType to match the Column interface.
      type: 'string' as LaravelColumnType, 
      nullable: false, 
      unique: false 
    };
    dispatchUpdate({
      // FIX: Removed @ts-ignore as the type is now correct.
      columns: [...data.columns, newCol]
    });
  };

  const updateColumn = (colId: string, field: string, value: any) => {
    const newCols = data.columns.map(c => 
      c.id === colId ? { ...c, [field]: value } : c
    );
    dispatchUpdate({ columns: newCols });
  };

  const removeColumn = (colId: string) => {
    dispatchUpdate({ columns: data.columns.filter(c => c.id !== colId) });
  };

  const changeColor = (color: string) => {
    dispatchUpdate({ color });
  };

  return (
    <div className="bg-white rounded-lg shadow-xl border border-slate-200 w-[280px] overflow-hidden text-sm flex flex-col">
      {/* Handles for connections */}
      <Handle type="target" position={Position.Left} className="!bg-slate-400 !w-3 !h-3 -ml-1.5" />
      <Handle type="source" position={Position.Right} className="!bg-slate-400 !w-3 !h-3 -mr-1.5" />

      {/* Header */}
      <div 
        className="px-3 py-2 flex items-center justify-between handle relative" 
        style={{ backgroundColor: data.color || '#3b82f6' }}
      >
        <div className="flex items-center gap-2 flex-1">
          <GripVertical size={14} className="text-white/50 cursor-grab active:cursor-grabbing" />
          <input 
            className="nodrag bg-transparent text-white font-bold placeholder-white/70 outline-none w-full"
            value={data.name}
            onChange={(e) => dispatchUpdate({ name: e.target.value })}
            placeholder="Table Name"
          />
        </div>
        <div className="flex items-center gap-1">
          {/* Color Picker (Hidden till hover usually, but let's put a small dot) */}
          <div className="group relative">
             <div className="w-3 h-3 rounded-full bg-white/30 cursor-pointer hover:bg-white border border-white/40"></div>
             <div className="absolute right-0 top-full mt-1 hidden group-hover:flex gap-1 p-1 bg-white shadow-lg rounded-md z-50 w-32 flex-wrap">
                {COLORS.map(c => (
                  <div 
                    key={c} 
                    className="w-4 h-4 rounded-full cursor-pointer hover:scale-110" 
                    style={{backgroundColor: c}}
                    onClick={() => changeColor(c)}
                  />
                ))}
             </div>
          </div>
          <button onClick={dispatchDelete} className="text-white/70 hover:text-white">
            <Trash2 size={14} />
          </button>
        </div>
      </div>

      {/* Columns List */}
      <div className="flex flex-col bg-white min-h-[50px] divide-y divide-slate-50">
        {data.columns.map((col) => (
          <ColumnRow 
            key={col.id} 
            column={col} 
            onUpdate={updateColumn} 
            onRemove={removeColumn} 
          />
        ))}
      </div>

      {/* Footer */}
      <button 
        onClick={addColumn}
        className="flex items-center justify-center gap-1 py-1.5 bg-slate-50 text-slate-500 hover:bg-slate-100 hover:text-slate-700 transition-colors border-t border-slate-100 text-xs font-medium"
      >
        <Plus size={12} /> Add Column
      </button>
    </div>
  );
};

export default memo(TableNode);

import React, { useState, useCallback, useEffect } from 'react';
import ReactFlow, { 
  addEdge, 
  Background, 
  Controls, 
  Connection, 
  Edge, 
  useNodesState, 
  useEdgesState,
  MiniMap,
  ReactFlowProvider
} from 'reactflow';
import { Plus, Download, Wand2, Database, Trash2, Github } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

import TableNode from './components/TableNode';
import { CodePreview } from './components/CodePreview';
// FIX: Import TableNode as TNode to avoid name collision with the component and correctly type the initial state.
import { GeneratedCode, TableNode as TNode } from './types';
import { generateLaravelMigrations } from './services/migrationGenerator';
import { generateSchemaFromPrompt } from './services/geminiService';
import { DEFAULT_COLUMNS, COLORS } from './constants';

const nodeTypes = {
  table: TableNode,
};

// Initial data
// FIX: Explicitly type initialNodes to align with the type returned by the AI service and prevent mismatches.
const initialNodes: TNode[] = [
  {
    id: '1',
    type: 'table',
    position: { x: 100, y: 100 },
    data: { 
      name: 'users', 
      color: COLORS[5],
      columns: [
        { id: 'c1', name: 'id', type: 'id', nullable: false, unique: true, isPrimaryKey: true },
        { id: 'c2', name: 'name', type: 'string', nullable: false, unique: false },
        { id: 'c3', name: 'email', type: 'string', nullable: false, unique: true },
        { id: 'c4', name: 'password', type: 'string', nullable: false, unique: false },
      ]
    },
  },
  {
    id: '2',
    type: 'table',
    position: { x: 500, y: 100 },
    data: { 
      name: 'posts', 
      color: COLORS[4],
      columns: [
        { id: 'p1', name: 'id', type: 'id', nullable: false, unique: true, isPrimaryKey: true },
        { id: 'p2', name: 'title', type: 'string', nullable: false, unique: false },
        { id: 'p3', name: 'content', type: 'text', nullable: true, unique: false },
      ]
    },
  },
];

const initialEdges: Edge[] = [
  { id: 'e1-2', source: '1', target: '2', label: 'hasMany', type: 'smoothstep', animated: true },
];

function SchemaDesigner() {
  const [nodes, setNodes, onNodesChange] = useNodesState(initialNodes);
  const [edges, setEdges, onEdgesChange] = useEdgesState(initialEdges);

  const [isExportOpen, setIsExportOpen] = useState(false);
  const [generatedFiles, setGeneratedFiles] = useState<GeneratedCode[]>([]);

  const [isAILoading, setIsAILoading] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [showAIPrompt, setShowAIPrompt] = useState(false);

  const onConnect = useCallback((params: Connection) => setEdges((eds) => addEdge({ ...params, type: 'smoothstep', animated: true, label: 'rel' }, eds)), [setEdges]);

  // Listen for custom events from Node components (Architecture choice to avoid passing setters deep)
  useEffect(() => {
    const handleNodeUpdate = (e: CustomEvent) => {
      const { id, data } = e.detail;
      setNodes((nds) => 
        nds.map((node) => {
          if (node.id === id) {
            return { ...node, data: { ...node.data, ...data } };
          }
          return node;
        })
      );
    };

    const handleNodeDelete = (e: CustomEvent) => {
      const { id } = e.detail;
      setNodes((nds) => nds.filter((n) => n.id !== id));
      setEdges((eds) => eds.filter((edge) => edge.source !== id && edge.target !== id));
    };

    window.addEventListener('node-data-update' as any, handleNodeUpdate);
    window.addEventListener('node-delete' as any, handleNodeDelete);

    return () => {
      window.removeEventListener('node-data-update' as any, handleNodeUpdate);
      window.removeEventListener('node-delete' as any, handleNodeDelete);
    };
  }, [setNodes, setEdges]);

  const addTable = () => {
    const id = uuidv4();
    const newNode = {
      id,
      type: 'table',
      position: { x: Math.random() * 400, y: Math.random() * 400 },
      data: {
        name: `table_${nodes.length + 1}`,
        columns: [...DEFAULT_COLUMNS],
        color: COLORS[Math.floor(Math.random() * COLORS.length)]
      }
    };
    setNodes((nds) => [...nds, newNode]);
  };

  const handleExport = () => {
    // FIX: Removed @ts-ignore as the `nodes` type is now correctly inferred.
    const codes = generateLaravelMigrations(nodes, edges);
    setGeneratedFiles(codes);
    setIsExportOpen(true);
  };

  const handleAIGenerate = async () => {
    if (!aiPrompt.trim()) return;
    setIsAILoading(true);
    try {
      const { nodes: newNodes, edges: newEdges } = await generateSchemaFromPrompt(aiPrompt);
      setNodes(newNodes);
      setEdges(newEdges);
      setShowAIPrompt(false);
      setAiPrompt('');
    } catch (error) {
      alert("Failed to generate schema. Please check your API Key and try again.");
    } finally {
      setIsAILoading(false);
    }
  };

  return (
    <div className="w-screen h-screen flex flex-col bg-slate-50">
      {/* Top Navbar */}
      <header className="h-16 bg-white border-b border-slate-200 px-6 flex items-center justify-between z-10 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-gradient-to-br from-red-500 to-orange-500 rounded-lg flex items-center justify-center text-white font-bold shadow-md">
            L
          </div>
          <h1 className="font-bold text-slate-800 text-lg tracking-tight">Laravel Schema <span className="text-slate-400 font-normal">Architect</span></h1>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={() => setShowAIPrompt(!showAIPrompt)}
            className="flex items-center gap-2 px-4 py-2 bg-purple-50 text-purple-600 rounded-lg hover:bg-purple-100 font-medium transition-colors border border-purple-200"
          >
            <Wand2 size={18} />
            <span className="hidden sm:inline">AI Designer</span>
          </button>

          <div className="h-6 w-px bg-slate-200 mx-2"></div>

          <button 
            onClick={addTable}
            className="flex items-center gap-2 px-4 py-2 bg-slate-100 text-slate-700 rounded-lg hover:bg-slate-200 font-medium transition-colors"
          >
            <Plus size={18} />
            <span className="hidden sm:inline">Add Table</span>
          </button>
          <button 
            onClick={handleExport}
            className="flex items-center gap-2 px-5 py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 font-medium shadow-lg shadow-slate-200 transition-all hover:scale-105"
          >
            <Download size={18} />
            Export Migrations
          </button>
        </div>
      </header>

      {/* AI Prompt Overlay */}
      {showAIPrompt && (
        <div className="absolute top-20 left-1/2 -translate-x-1/2 w-[500px] z-50 bg-white p-4 rounded-xl shadow-2xl border border-purple-100 animate-in fade-in zoom-in duration-200">
           <h3 className="font-bold text-slate-800 mb-2 flex items-center gap-2">
             <Wand2 size={16} className="text-purple-500"/> Describe your app
           </h3>
           <textarea 
             className="w-full h-32 p-3 bg-slate-50 rounded-lg border border-slate-200 focus:border-purple-500 focus:ring-2 focus:ring-purple-100 outline-none resize-none text-sm"
             placeholder="e.g. A library management system with books, authors, members and loans..."
             value={aiPrompt}
             onChange={e => setAiPrompt(e.target.value)}
           />
           <div className="flex justify-end gap-2 mt-3">
             <button onClick={() => setShowAIPrompt(false)} className="px-3 py-1.5 text-slate-500 text-sm hover:bg-slate-100 rounded-md">Cancel</button>
             <button 
               onClick={handleAIGenerate}
               disabled={isAILoading}
               className="px-4 py-1.5 bg-purple-600 text-white text-sm font-medium rounded-md hover:bg-purple-700 disabled:opacity-50 flex items-center gap-2"
             >
               {isAILoading ? 'Thinking...' : 'Generate Schema'}
             </button>
           </div>
        </div>
      )}

      {/* Canvas */}
      <div className="flex-1 w-full h-full relative">
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
          nodeTypes={nodeTypes}
          fitView
          className="bg-slate-50"
          defaultEdgeOptions={{ type: 'smoothstep', animated: true, style: { strokeWidth: 2, stroke: '#94a3b8' } }}
        >
          <Background color="#cbd5e1" gap={20} size={1} />
          <Controls className="!bg-white !border-slate-200 !shadow-lg !rounded-lg !p-1" />
          <MiniMap 
            className="!bg-white !border-slate-200 !shadow-lg !rounded-lg" 
            maskColor="rgba(241, 245, 249, 0.7)"
            // FIX: Provide a fallback color to handle cases where node.data.color is undefined.
            nodeColor={(n) => n.data.color || '#3b82f6'} 
          />
        </ReactFlow>

        {/* Helper Text */}
        {nodes.length === 0 && (
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <div className="text-center text-slate-400">
              <Database size={48} className="mx-auto mb-2 opacity-20" />
              <p className="font-medium">Canvas is empty</p>
              <p className="text-sm">Add a table or use AI to start</p>
            </div>
          </div>
        )}
      </div>

      <CodePreview 
        isOpen={isExportOpen} 
        onClose={() => setIsExportOpen(false)} 
        files={generatedFiles} 
      />
    </div>
  );
}

export default function App() {
  return (
    <ReactFlowProvider>
      <SchemaDesigner />
    </ReactFlowProvider>
  );
}

import React, { useState } from 'react';
import { X, Copy, Download, Code } from 'lucide-react';
import JSZip from 'jszip';
import { GeneratedCode } from '../types';

interface Props {
  files: GeneratedCode[];
  isOpen: boolean;
  onClose: () => void;
}

export const CodePreview: React.FC<Props> = ({ files, isOpen, onClose }) => {
  const [activeFileIndex, setActiveFileIndex] = useState(0);

  const handleDownloadZip = async () => {
    if (files.length === 0) return;

    const zip = new JSZip();
    // Place all generated files into a 'migrations' folder inside the zip
    const migrationsFolder = zip.folder("migrations");

    files.forEach(file => {
      migrationsFolder?.file(file.filename, file.content);
    });

    try {
      const blob = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(blob);
      link.download = `laravel-migrations-${Date.now()}.zip`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(link.href);
    } catch (error) {
      console.error("Failed to generate zip file:", error);
      alert("There was an error creating the zip file.");
    }
  };

  if (!isOpen) return null;

  const activeFile = files[activeFileIndex];

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl h-[80vh] flex flex-col overflow-hidden">

        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-slate-100 bg-slate-50">
          <div className="flex items-center gap-2">
            <div className="p-2 bg-blue-100 text-blue-600 rounded-lg">
              <Code size={20} />
            </div>
            <div>
              <h2 className="font-bold text-slate-800">Generated Migrations</h2>
              <p className="text-xs text-slate-500">Ready for artisan migrate</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-200 rounded-full text-slate-500">
            <X size={20} />
          </button>
        </div>

        {/* Content */}
        <div className="flex flex-1 overflow-hidden">
          {/* Sidebar Files List */}
          <div className="w-1/3 bg-slate-50 border-r border-slate-200 overflow-y-auto">
            {files.map((file, idx) => (
              <button
                key={file.filename}
                onClick={() => setActiveFileIndex(idx)}
                className={`w-full text-left px-4 py-3 text-xs font-mono border-b border-slate-100 transition-colors ${
                  activeFileIndex === idx 
                    ? 'bg-white border-l-4 border-l-blue-500 text-blue-700 font-medium shadow-sm' 
                    : 'text-slate-600 hover:bg-slate-100'
                }`}
              >
                {file.filename}
              </button>
            ))}
          </div>

          {/* Code Viewer */}
          <div className="w-2/3 flex flex-col bg-[#1e293b]">
            <div className="flex items-center justify-between px-4 py-2 bg-[#0f172a] text-slate-400 text-xs border-b border-slate-700">
              <span className="font-mono">{activeFile?.filename}</span>
              <div className="flex gap-2">
                 <button 
                  onClick={() => activeFile && navigator.clipboard.writeText(activeFile.content)}
                  className="flex items-center gap-1 hover:text-white"
                 >
                   <Copy size={12} /> Copy
                 </button>
              </div>
            </div>
            <div className="flex-1 overflow-auto p-4">
              <pre className="font-mono text-xs text-blue-100 leading-relaxed">
                <code>{activeFile?.content}</code>
              </pre>
            </div>
          </div>
        </div>

        {/* Footer Actions */}
        <div className="px-6 py-4 border-t border-slate-100 bg-white flex justify-end gap-3">
            <button onClick={onClose} className="px-4 py-2 text-slate-600 font-medium text-sm hover:bg-slate-100 rounded-lg">
                Close
            </button>
            <button 
              onClick={handleDownloadZip}
              className="px-4 py-2 bg-blue-600 text-white font-medium text-sm hover:bg-blue-700 rounded-lg shadow-lg shadow-blue-200 flex items-center gap-2"
            >
                <Download size={16} /> Download All (.zip)
            </button>
        </div>

      </div>
    </div>
  );
};
